+import { readFile } from 'node:fs/promises';
+import { resolve } from 'node:path';
+
+type PlanStep = {
+  status?: string;
+};
+
+type PlanFile = {
+  steps?: PlanStep[];
+};
+
+const DEFAULT_FILE = 'translations-removal-plan.json';
+const CHECK_INTERVAL_MS = 10_000;
+
+const planPath = resolve(process.cwd(), process.argv[2] ?? DEFAULT_FILE);
+
+const formatCounts = (counts: Record<string, number>) => {
+  const entries = Object.entries(counts).sort(([a], [b]) => a.localeCompare(b));
+  return entries.map(([status, count]) => `${status}: ${count}`).join(' | ');
+};
+
+const readCounts = async () => {
+  const raw = await readFile(planPath, 'utf8');
+  const parsed = JSON.parse(raw) as PlanFile;
+  const counts: Record<string, number> = {};
+
+  for (const step of parsed.steps ?? []) {
+    const status = step.status ?? 'unknown';
+    counts[status] = (counts[status] ?? 0) + 1;
+  }
+
+  return counts;
+};
+
+const tick = async () => {
+  try {
+    const counts = await readCounts();
+    const timestamp = new Date().toISOString();
+    console.clear();
+    console.log(`[${timestamp}] ${planPath}`);
+    console.log(formatCounts(counts));
+  } catch (error) {
+    console.clear();
+    console.error('Failed to read or parse plan file:', planPath);
+    console.error(error);
+  }
+};
+
+void tick();
+setInterval(() => {
+  void tick();
+}, CHECK_INTERVAL_MS);
